import{_ as o,c as t,o as s,a5 as i,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.13: Desktop Session Forking, Search Follows Symlinks","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.13.md","filePath":"en/changelog/v1.1.13.md","lastUpdated":1772014034000}'),r={name:"en/changelog/v1.1.13.md"};function n(l,a,p,d,h,c){return s(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="v1-1-13-desktop-session-forking-search-follows-symlinks" tabindex="-1">v1.1.13: Desktop Session Forking, Search Follows Symlinks <a class="header-anchor" href="#v1-1-13-desktop-session-forking-search-follows-symlinks" aria-label="Permalink to “v1.1.13: Desktop Session Forking, Search Follows Symlinks”">​</a></h1><p><strong>Release Date</strong>: January 11, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update adds <strong>session forking</strong> to the desktop app, ripgrep search <strong>follows symlinks by default</strong>, and fixes multiple UI issues.</p><hr><h2 id="new-feature-desktop-session-forking" tabindex="-1">New Feature: Desktop Session Forking <a class="header-anchor" href="#new-feature-desktop-session-forking" aria-label="Permalink to “New Feature: Desktop Session Forking”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>The desktop app now supports <strong>forking sessions</strong> from any message point, creating new conversation branches. This means you can:</p><ul><li>Try different directions from a key decision point</li><li>Explore new ideas while preserving original conversation</li><li>Compare effects of different approaches</li></ul><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3><p>In the desktop app:</p><ol><li>Find the message you want to fork from</li><li>Right-click that message</li><li>Select <strong>Fork Session</strong></li><li>New session starts from that message point, preserving previous context</li></ol><hr><h2 id="improvement-ripgrep-search-follows-symlinks" tabindex="-1">Improvement: Ripgrep Search Follows Symlinks <a class="header-anchor" href="#improvement-ripgrep-search-follows-symlinks" aria-label="Permalink to “Improvement: Ripgrep Search Follows Symlinks”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When using Grep tool to search code, if the project has <strong>symlinks</strong> pointing to other directories, files in those directories wouldn&#39;t be searched.</p><p>Common scenarios:</p><ul><li>Shared packages in monorepo</li><li>Linked packages in node_modules</li><li>Custom directory soft links</li></ul><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to “Current Behavior”">​</a></h3><p>OpenCode&#39;s ripgrep search now <strong>follows symlinks by default</strong>:</p><ul><li>✅ Files in symlinked directories will be searched</li><li>✅ More complete search results</li><li>✅ No extra configuration needed</li></ul><hr><h2 id="other-improvements" tabindex="-1">Other Improvements <a class="header-anchor" href="#other-improvements" aria-label="Permalink to “Other Improvements”">​</a></h2><h3 id="command-palette-fix" tabindex="-1">Command Palette Fix <a class="header-anchor" href="#command-palette-fix" aria-label="Permalink to “Command Palette Fix”">​</a></h3><p>Previously in TUI, when using command palette, mouse hover might highlight wrong options. Now fixed, both mouse and keyboard operations respond correctly.</p><h3 id="prompt-input-autocomplete" tabindex="-1">Prompt Input Autocomplete <a class="header-anchor" href="#prompt-input-autocomplete" aria-label="Permalink to “Prompt Input Autocomplete”">​</a></h3><p>Desktop prompt input box now supports:</p><ul><li>Mouse hover to preview autocomplete options</li><li>Click to directly select autocomplete item</li></ul><h3 id="openai-business-support" tabindex="-1">OpenAI Business Support <a class="header-anchor" href="#openai-business-support" aria-label="Permalink to “OpenAI Business Support”">​</a></h3><p><code>/connect</code> command now fully supports OpenAI Business plan, resolving previous missing fields issue.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using desktop app</td><td>✅ Upgrade, experience session forking</td></tr><tr><td>Project has symlinks</td><td>✅ Upgrade, more complete search</td></tr><tr><td>Using OpenAI Business</td><td>✅ Upgrade, /connect more stable</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',35),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Codex built-in plugin always available</li><li><code>/connect</code> supports OpenAI Business plan (add missing fields)</li><li>ACP tracks file modifications (@wid4t)</li><li>Pass sessionID to chat.system.transform (@spoons-and-mirrors)</li><li>Extract external directory validation to shared utility function, reduce code duplication</li><li>Exclude &#39;none&#39; variant for gpt-5.2-codex (@Alejandro-CSt)</li><li>Ripgrep search follows symlinks by default (@kdcokenny)</li><li>Disable PHP language server telemetry (@madflow)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Fix TUI component props.ref issue (@itsrainingmani)</li><li>Fix command palette mouse hover highlighting wrong item (@kitlangton)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Add session forking feature (@dbpolito)</li><li>Prompt input autocomplete supports mouse hover and click (@dbpolito)</li><li>Add missing StoreExt import, fix unused mut warning (@jerome-benoit)</li><li>Fix missing import causing desktop build failure (@Leka74)</li><li>Support configuring default server URL (@athal7)</li><li>Remove split operation in serverDisplayName function (@OpeOginni)</li></ul><h3 id="community-contributors" tabindex="-1">Community Contributors <a class="header-anchor" href="#community-contributors" aria-label="Permalink to “Community Contributors”">​</a></h3><p>Thanks to 13 community contributors: @madflow, @dbpolito, @zerone0x, @OpeOginni, @athal7, @kdcokenny, @Alejandro-CSt, @Leka74, @jerome-benoit, @spoons-and-mirrors, @kitlangton, @wid4t, @itsrainingmani</p></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=o(r,[["render",n]]);export{u as __pageData,g as default};
